/**
 * ClawHarness Eval Plugin for OpenClaw
 *
 * Reads tool definitions from /tmp/eval-tools.json (generated by the
 * entrypoint from task.yaml + mock service OpenAPI spec) and registers
 * each mock-service endpoint as a native OpenClaw tool.
 *
 * The agent sees tools like `create_task`, `list_tasks` etc. — identical
 * to how it sees `sendSlackMessage` or `web_fetch`.  Tool execute()
 * makes a direct HTTP call to the mock service on localhost, completely
 * bypassing SSRF checks (since it's an internal tool, not web_fetch).
 */

import { Type } from "@sinclair/typebox";
import * as fs from "node:fs";
import * as http from "node:http";

const TOOLS_FILE = process.env.EVAL_TOOLS_FILE || "/tmp/eval-tools.json";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface ToolDef {
  name: string;
  description: string;
  endpoint: string;
  method: string;
  port: number;
  parameters: Record<string, any>;
  required: string[];
}

// ---------------------------------------------------------------------------
// HTTP helper — direct localhost call, no SSRF involved
// ---------------------------------------------------------------------------

function makeRequest(
  port: number,
  path: string,
  method: string,
  body: any,
): Promise<any> {
  return new Promise((resolve, reject) => {
    const req = http.request(
      {
        hostname: "127.0.0.1",
        port,
        path,
        method: method.toUpperCase(),
        headers: { "Content-Type": "application/json" },
      },
      (res) => {
        let data = "";
        res.on("data", (chunk: string) => (data += chunk));
        res.on("end", () => {
          try {
            resolve(JSON.parse(data));
          } catch {
            resolve({ raw: data });
          }
        });
      },
    );
    req.on("error", reject);
    req.setTimeout(30_000, () => req.destroy(new Error("Request timeout")));
    if (body !== undefined && body !== null) {
      req.write(JSON.stringify(body));
    }
    req.end();
  });
}

// ---------------------------------------------------------------------------
// OpenAPI property → TypeBox schema
// ---------------------------------------------------------------------------

function openApiPropToTypeBox(
  key: string,
  schema: any,
  required: string[],
): any {
  const isRequired = required.includes(key);
  const desc = schema.title || schema.description || key;

  // Handle Pydantic nullable: anyOf: [{type: "string"}, {type: "null"}]
  let effectiveType = schema.type;
  if (schema.anyOf) {
    const nonNull = schema.anyOf.find((s: any) => s.type !== "null");
    if (nonNull) effectiveType = nonNull.type;
  }

  let tb: any;
  switch (effectiveType) {
    case "string":
      tb = Type.String({ description: desc });
      break;
    case "integer":
    case "number":
      tb = Type.Number({ description: desc });
      break;
    case "boolean":
      tb = Type.Boolean({ description: desc });
      break;
    case "array":
      tb = Type.Array(Type.String(), { description: desc });
      break;
    default:
      // Unknown type — accept any string
      tb = Type.String({ description: desc });
  }

  return isRequired ? tb : Type.Optional(tb);
}

function buildSchema(toolDef: ToolDef): any {
  const properties: Record<string, any> = {};
  const required = toolDef.required || [];

  for (const [key, schema] of Object.entries(toolDef.parameters || {})) {
    properties[key] = openApiPropToTypeBox(key, schema, required);
  }

  return Type.Object(properties);
}

// ---------------------------------------------------------------------------
// Tool factory
// ---------------------------------------------------------------------------

function createEvalTool(toolDef: ToolDef): any {
  const schema = buildSchema(toolDef);

  return {
    name: toolDef.name,
    label: toolDef.name
      .replace(/_/g, " ")
      .replace(/\b\w/g, (c) => c.toUpperCase()),
    description: toolDef.description,
    parameters: schema,
    async execute(_toolCallId: string, args: Record<string, unknown>) {
      try {
        const result = await makeRequest(
          toolDef.port,
          toolDef.endpoint,
          toolDef.method,
          args,
        );
        return {
          content: [
            { type: "text" as const, text: JSON.stringify(result, null, 2) },
          ],
          details: result,
        };
      } catch (err: any) {
        return {
          content: [
            {
              type: "text" as const,
              text: `Error calling ${toolDef.name}: ${err.message}`,
            },
          ],
        };
      }
    },
  };
}

// ---------------------------------------------------------------------------
// Plugin entry point
// ---------------------------------------------------------------------------

const plugin = {
  id: "clawharness-eval",
  name: "ClawHarness Eval Tools",
  description:
    "Registers mock service endpoints as native agent tools for evaluation.",
  configSchema: {
    type: "object" as const,
    additionalProperties: false,
    properties: {},
  },

  register(api: any) {
    if (!fs.existsSync(TOOLS_FILE)) {
      api.logger?.warn?.(`[clawharness-eval] No tools file at ${TOOLS_FILE}`);
      return;
    }

    let tools: ToolDef[];
    try {
      tools = JSON.parse(fs.readFileSync(TOOLS_FILE, "utf8"));
    } catch (err: any) {
      api.logger?.error?.(
        `[clawharness-eval] Failed to read tools: ${err.message}`,
      );
      return;
    }

    if (!Array.isArray(tools) || tools.length === 0) {
      api.logger?.warn?.("[clawharness-eval] No tools defined");
      return;
    }

    for (const toolDef of tools) {
      try {
        const tool = createEvalTool(toolDef);
        api.registerTool(tool, { name: toolDef.name });
      } catch (err: any) {
        api.logger?.error?.(
          `[clawharness-eval] Failed to register ${toolDef.name}: ${err.message}`,
        );
      }
    }

    api.logger?.info?.(
      `[clawharness-eval] Registered ${tools.length} eval tools`,
    );
  },
};

export default plugin;
